SELECT * FROM (
    SELECT 1 as c, 2 as d
    UNION ALL
    SELECT 1 as c, 3 AS d
) as a FULL JOIN (SELECT 1 as e, 3 AS f) AS rhs ON a.c=rhs.e;

WITH t1 (k) AS (
    VALUES (1), (2)
), t2 (k) AS (
    VALUES (1)
)
SELECT *
FROM t1
LEFT ANTI JOIN (
    SELECT *
    FROM t2
    WHERE k <> 1
) t2 ON t1.k = t2.k;

SELECT t1.c0, t1.c1, t1.c2
FROM t1_c t1
INNER JOIN t2_c t2 ON t1.c0 = t2.c0;

SELECT t1.c0, t1.c1, t1.c2
FROM t1_c t1
INNER JOIN t2_c t2 ON t1.c0 = t2.c0 AND t1.c1 = t2.c1;

SELECT sub.a, sub.b FROM (
  SELECT * FROM t1 ORDER BY b LIMIT 1
) sub
JOIN t2 ON sub.a = t2.c;

WITH RECURSIVE my_cte AS(
    SELECT 1::int AS a
    UNION ALL
    SELECT a::bigint+2 FROM my_cte WHERE a<3
) SELECT *, arrow_typeof(a) FROM my_cte;

WITH RECURSIVE my_cte AS (
    SELECT 1::bigint AS a
    UNION ALL
    SELECT a+2, 'a','c' FROM my_cte WHERE a<3
) SELECT * FROM my_cte;

WITH RECURSIVE my_cte AS (
    SELECT 1 AS a
    UNION ALL
    SELECT 'abc' FROM my_cte WHERE CAST(a AS text) !='abc'
) SELECT * FROM my_cte;

WITH RECURSIVE cte AS (
    SELECT a FROM (VALUES(1)) AS t(a) WHERE a > 2
    UNION ALL
    SELECT 2
) SELECT * FROM cte;

WITH RECURSIVE cte AS (
    SELECT 1
    UNION ALL
    SELECT 2
) SELECT * FROM cte;

WITH RECURSIVE cte AS (
    SELECT 2
    UNION
    SELECT 2
) SELECT * FROM cte;

WITH RECURSIVE cte AS (
    SELECT 1
) SELECT * FROM cte;

WITH RECURSIVE
non_recursive_cte AS (
  SELECT 1
),
recursive_cte AS (
  SELECT 1 AS a UNION ALL SELECT a+2 FROM recursive_cte WHERE a < 3
)
SELECT * FROM non_recursive_cte, recursive_cte;

SELECT id, parent_id, ts, val
  FROM cte_schema_reread
  WHERE id = 'id';

select t1_id
from t1
where t1_int = (select max(i) from (values (1)) as s(i));

select o_orderkey from orders
where o_orderstatus in (
    select l_linestatus from lineitem where l_orderkey = orders.o_orderkey
);

select t1.t1_int from t1 where (
    select cnt_plus_one + 1 as cnt_plus_two from (
        select cnt + 1 as cnt_plus_one from (
            select count(*) as cnt, sum(t2_int) s from t2 where t1.t1_int = t2.t2_int having cnt = 0
        )
    )
) = 2

SELECT CASE WHEN x > (SELECT min(v) FROM sq_values)
            THEN 'big' ELSE 'small' END AS label
FROM sq_main;

SELECT i
FROM generate_series(1, 10) AS t(i)
WHERE i > (
  SELECT avg(j) FROM generate_series(1, 10) AS u(j)
)
ORDER BY i;

SELECT l.x, r.x AS rx
FROM sq_main AS l JOIN sq_main AS r
ON l.x = r.x + (SELECT min(v) FROM sq_values);

SELECT count(DISTINCT r) = 1 FROM (
  SELECT (SELECT random()) AS r
  FROM (VALUES (1), (2), (3)) AS t(x)
);

SELECT x FROM (VALUES (1), (2), (3), (4), (5)) AS t(x)
WHERE x BETWEEN (SELECT 2) AND (SELECT 4)
ORDER BY x;

SELECT * FROM dup_filter_t1 WHERE dup_filter_t1.id IN (
    SELECT dup_filter_t2.id FROM dup_filter_t2 WHERE dup_filter_t2.id > dup_filter_t1.id
);

SELECT column1, column2 FROM subquery_partitioned
WHERE part = (SELECT 1)
ORDER BY column1;

select cntrycode, count(*) as numcust, sum(c_acctbal) as totacctbal
from (
    select substring(c_phone from 1 for 2) as cntrycode, c_acctbal
    from sq_count_customer
    where c_acctbal > (
        select avg(c_acctbal) from sq_count_customer where c_acctbal > 0.00
    )
      and not exists (
        select * from sq_count_orders where o_custkey = c_custkey
      )
) as custsale
group by cntrycode
order by cntrycode;

select count(*) from (
    select cntrycode, count(*) as numcust, sum(c_acctbal) as totacctbal
    from (
        select substring(c_phone from 1 for 2) as cntrycode, c_acctbal
        from sq_count_customer
        where c_acctbal > (
            select avg(c_acctbal) from sq_count_customer where c_acctbal > 0.00
        )
          and not exists (
            select * from sq_count_orders where o_custkey = c_custkey
          )
    ) as custsale
    group by cntrycode
) as q;

SELECT sub.col1, sub.col0, sub."avg(tab3.col2)" AS avg_col2
FROM (
  SELECT col1, avg(col2), col0 FROM tab3 GROUP BY ALL
) AS sub
GROUP BY ALL;

SELECT a, b, ARRAY_AGG(d ORDER BY d)
FROM annotated_data_infinite2
GROUP BY a, b;

SELECT a, b, d
FROM annotated_data_infinite2
ORDER BY a, b, d;

select t1.b, c, c2 FROM (
  select b, c FROM ordered_table ORDER BY b desc, c desc OFFSET 1 LIMIT 4
) as t1 INNER JOIN (
  select b, c as c2 FROM ordered_table ORDER BY b desc, d desc OFFSET 1 LIMIT 4
) as t2
ON t1.b = t2.b
ORDER BY t1.b desc, c desc, c2 desc;

select t1.b, c, c2 FROM (
  select b, c FROM ordered_table ORDER BY b desc, c desc OFFSET 1 LIMIT 4
) as t1 INNER JOIN (
  select b, c as c2 FROM ordered_table ORDER BY b desc, d desc OFFSET 1 LIMIT 4
) as t2
ON t1.b = t2.b
ORDER BY t1.b desc, c desc, c2 desc
OFFSET 3 LIMIT 2;

SELECT * FROM (
  SELECT g, SUM(x) AS sx, SUM(y) AS sy FROM t22489 GROUP BY g
  ORDER BY sx DESC LIMIT 4
) q
ORDER BY sy DESC
OFFSET 1;

